def create_invoice(
    amount_cents: int,
    currency: str,
    due_date: str,
) -> dict:
    if amount_cents <= 0:
        return {
            "error": "VALIDATION_ERROR",
            "message": "amount_cents must be a positive integer.",
            "retryable": False,
            "details": {"field": "amount_cents", "received": amount_cents},
        }
    if currency not in {"USD", "EUR", "GBP"}:
        return {
            "error": "VALIDATION_ERROR",
            "message": f"currency must be one of USD, EUR, GBP. Got {currency!r}.",
            "retryable": False,
            "details": {"field": "currency", "allowed": ["USD", "EUR", "GBP"]},
        }
    return _create(amount_cents, currency, due_date)

import time

def call_external_api(payload: dict) -> dict:
    try:
        resp = _http_client.post("/api", json=payload)
    except RateLimitError as exc:
        return {
            "error": "RATE_LIMITED",
            "message": "API rate limit reached. Retry after the indicated delay.",
            "retryable": True,
            "retry_after": exc.retry_after,  # seconds
        }
    except ServiceUnavailableError:
        return {
            "error": "SERVICE_UNAVAILABLE",
            "message": "Upstream service is temporarily unavailable.",
            "retryable": True,
            "retry_after": 5,
        }
    return resp.json()

import anthropic

client = anthropic.Anthropic()

def safe_tool_handler(tool_name: str, tool_input: dict) -> dict:
    """Wrap any tool call so exceptions become structured errors."""
    try:
        if tool_name == "get_user":
            return get_user(**tool_input)
        if tool_name == "create_invoice":
            return create_invoice(**tool_input)
        return {"error": "UNKNOWN_TOOL", "message": f"No handler for {tool_name}", "retryable": False}
    except Exception as exc:
        # Last-resort catch — ideally each handler catches its own errors
        return {
            "error": "INTERNAL_ERROR",
            "message": "An unexpected error occurred. Please try again later.",
            "retryable": True,
        }

# In the agentic loop
def run_tool_use_loop(messages: list, tools: list) -> str:
    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if b.type == "text")
        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = safe_tool_handler(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })
        messages.append({"role": "user", "content": tool_results})

