from pydantic import BaseModel, field_validator, ValidationError
import json

class BookFlightInput(BaseModel):
    origin: str          # IATA code, e.g. "LHR"
    destination: str
    departure_date: str  # ISO 8601, e.g. "2025-03-15"
    passengers: int

    @field_validator("origin", "destination")
    @classmethod
    def must_be_iata(cls, v: str) -> str:
        if len(v) != 3 or not v.isalpha():
            raise ValueError(f"{v!r} is not a valid 3-letter IATA airport code")
        return v.upper()

    @field_validator("passengers")
    @classmethod
    def positive(cls, v: int) -> int:
        if v < 1 or v > 9:
            raise ValueError("passengers must be between 1 and 9")
        return v

def book_flight(raw_input: dict) -> dict:
    try:
        params = BookFlightInput(**raw_input)
    except ValidationError as exc:
        errors = exc.errors()
        first = errors[0]
        return {
            "error": "VALIDATION_ERROR",
            "message": f"Invalid input for field '{'.'.join(str(l) for l in first['loc'])}': {first['msg']}",
            "retryable": False,
            "details": {"validation_errors": errors},
        }
    return _do_booking(params)

def create_user(email: str, name: str) -> dict:
    existing = db.find_user_by_email(email)
    if existing is not None:
        return {
            "error": "CONFLICT",
            "message": f"A user with email {email!r} already exists.",
            "retryable": False,
            "details": {"existing_user_id": existing.id},
        }
    user = db.create_user(email=email, name=name)
    return {"id": user.id, "email": user.email, "name": user.name}
